const attrs = (msg.data && msg.data.new_state && msg.data.new_state.attributes) || {};
msg.run_id = attrs.run_id || '';
msg.restart = attrs.restart === true || attrs.restart === 'true';
return msg;

const raw = (msg.payload && msg.payload.toString) ? msg.payload.toString() : String(msg.payload || '');
msg.stderr_buffer = raw.slice(0, 220);
return msg;

const code = (msg.payload && typeof msg.payload === 'object') ? msg.payload.code : Number(msg.payload);
const runId = msg.run_id || 'unknown';
if (code === 0) {
  msg.payload = runId + '|node_red|success|0';
  msg.success = true;
  return [msg, null];
}
msg.payload = runId + '|node_red|failure|' + code;
msg.success = false;
return [null, msg];
